-- Infrastructure: auto-update updated_at on row modification.
-- This function is called by triggers on every resource table.
-- Do NOT remove — all migrations generated by 'axe generate resource' depend on it.
CREATE OR REPLACE FUNCTION trigger_set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
